// Firestore runQuery का response parse करो
const out = [];
for (const item of $input.all()) {
  const doc = item.json.document;
  if (!doc) continue;
  const f = doc.fields || {};
  const v = (k) => f[k]?.stringValue ?? f[k]?.doubleValue ?? f[k]?.integerValue ?? '';
  const createdAt = v('createdAt');
  const ageHours = createdAt ? (Date.now() - new Date(createdAt).getTime()) / 36e5 : 0;
  out.push({ json: {
    docName: doc.name,               // full Firestore path (PATCH के लिए)
    staff_phone: String(v('staff_phone')),
    staff_name: v('staff_name'),
    amount: Number(v('amount')) || 0,
    firm: v('firm'),
    expense_id: v('expense_id'),
    link: v('link') || 'https://vikram7charan-del.github.io/vbe-order-tracker/kharcha-entry.html',
    escalated: f.escalated?.booleanValue === true,
    ageHours: Math.round(ageHours)
  }});
}
return out;
